'use client'

import { useState, useEffect, useMemo, useCallback } from 'react'
import { Button, Badge, Card } from '@/components/ui'
import { supabase } from '@/lib/supabase'
import skuData from '@/lib/sku-data.json'

interface ReturnExchangeData {
  id?: number
  year: number
  month: number
  day: number
  distributor: string
  type: '교환' | '반품'
  payment_method: string
  recipient: string
  original_tracking: string
  return_tracking: string
  order_no: string
  reason: string
  category: string
  product_name: string
  quantity: number
  defect_level: '미결함' | '경결함'
  internal_notes: string
  customer_voc: string
  cash_receipt_issued: boolean
  amount: string
  notes: string
  receipt_delivered: boolean
  receipt_details: string
  barcode: string
}

const reasons = [
  '색상/사이즈 변경',
  '상품불량',
  '단순변심',
  '주문착오',
  '서비스/상품불만족',
  '오배송'
]

const distributors = [
  '아임웹',
  '스마트스토어',
  '오늘의집',
  '29CM',
  '무신사',
  'CJ온스타일',
  '텐바이텐',
  '카카오톡스토어',
  '아임웹(공구)',
  '카카오톡선물하기',
  '협찬',
  'W컨셉'
]

interface ProductItem {
  category: string
  product_name: string
  barcode: string
  quantity: number
}

export default function ReturnsPage() {
  const [showForm, setShowForm] = useState(false)
  const [returnsList, setReturnsList] = useState<ReturnExchangeData[]>([])
  const [formData, setFormData] = useState<Partial<ReturnExchangeData>>({
    year: new Date().getFullYear(),
    month: new Date().getMonth() + 1,
    day: new Date().getDate(),
    type: '반품',
    defect_level: '미결함',
    cash_receipt_issued: false,
    receipt_delivered: false
  })
  // 여러 상품 입력을 위한 배열
  const [products, setProducts] = useState<ProductItem[]>([
    { category: '', product_name: '', barcode: '', quantity: 1 }
  ])
  const [isLoadingOrder, setIsLoadingOrder] = useState(false)
  const [barcodeSearch, setBarcodeSearch] = useState('')
  const [showBarcodeResults, setShowBarcodeResults] = useState(false)
  const [currentProductIndex, setCurrentProductIndex] = useState(0)
  const [selectedItem, setSelectedItem] = useState<ReturnExchangeData | null>(null)
  const [relatedItems, setRelatedItems] = useState<ReturnExchangeData[]>([]) // 같은 주문번호의 모든 제품
  const [showDetailModal, setShowDetailModal] = useState(false)
  const [showAddProductForm, setShowAddProductForm] = useState(false) // 상품 추가 폼 표시
  const [newProduct, setNewProduct] = useState<ProductItem>({ category: '', product_name: '', barcode: '', quantity: 1 }) // 추가할 상품
  const [editData, setEditData] = useState<Partial<ReturnExchangeData>>({})
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc')
  const [searchQuery, setSearchQuery] = useState('')
  // 필터 상태
  const [filterType, setFilterType] = useState<string>('')
  const [filterReason, setFilterReason] = useState<string>('')
  const [filterReceipt, setFilterReceipt] = useState<string>('')
  const [activeTab, setActiveTab] = useState<'rug' | 'furniture'>('rug')
  const [currentPage, setCurrentPage] = useState(1)
  const [isLoading, setIsLoading] = useState(true)
  const itemsPerPage = 50 // 페이지당 50개 항목

  // 가구 판단 함수 (카테고리에 가구 키워드 포함)
  const isFurniture = (category: string) => {
    const furnitureKeywords = ['가구', '테이블', '의자', '선반', '스툴', '체어', '책상', '소파']
    return furnitureKeywords.some(keyword => category?.includes(keyword))
  }

  // 검색 + 필터 + 탭 + 날짜별 정렬된 리스트
  const filteredAndSortedList = useMemo(() => {
    return [...returnsList]
      .filter(item => {
        // 탭 필터 (가구 / 러그&기타)
        const itemIsFurniture = isFurniture(item.category || '')
        if (activeTab === 'furniture' && !itemIsFurniture) return false
        if (activeTab === 'rug' && itemIsFurniture) return false

        // 검색어 필터
        if (searchQuery) {
          const query = searchQuery.toLowerCase()
          const match = (
            item.order_no?.toLowerCase().includes(query) ||
            item.recipient?.toLowerCase().includes(query) ||
            item.barcode?.toLowerCase().includes(query) ||
            item.product_name?.toLowerCase().includes(query)
          )
          if (!match) return false
        }
        // 구분 필터
        if (filterType && item.type !== filterType) return false
        // 사유 필터
        if (filterReason && item.reason !== filterReason) return false
        // 현금영수증 발급 필터
        if (filterReceipt === 'issued' && !item.cash_receipt_issued) return false
        if (filterReceipt === 'not_issued' && item.cash_receipt_issued) return false

        return true
      })
      .sort((a, b) => {
        const dateA = new Date(a.year, a.month - 1, a.day).getTime()
        const dateB = new Date(b.year, b.month - 1, b.day).getTime()
        return sortOrder === 'asc' ? dateA - dateB : dateB - dateA
      })
  }, [returnsList, activeTab, searchQuery, filterType, filterReason, filterReceipt, sortOrder])

  // 페이지네이션 적용
  const paginatedList = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage
    const endIndex = startIndex + itemsPerPage
    return filteredAndSortedList.slice(startIndex, endIndex)
  }, [filteredAndSortedList, currentPage, itemsPerPage])

  const totalPages = Math.ceil(filteredAndSortedList.length / itemsPerPage)

  // 페이지 변경 시 맨 위로 스크롤
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }, [currentPage])

  // 필터/검색 변경 시 1페이지로 리셋
  useEffect(() => {
    setCurrentPage(1)
  }, [activeTab, searchQuery, filterType, filterReason, filterReceipt])

  // 정렬 토글
  const toggleSort = useCallback(() => {
    setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc')
  }, [])

  // 디바운스 타이머 ref
  const debounceTimers = useState<Record<string, NodeJS.Timeout>>({})[0]

  // 인라인 필드 업데이트 (Optimistic update: 화면 먼저 → DB 백그라운드)
  const updateInlineField = (id: number, field: string, value: any) => {
    // 즉시 화면 반영
    setReturnsList(prev =>
      prev.map(item => item.id === id ? { ...item, [field]: value } : item)
    )

    // 텍스트 필드는 디바운스 (타이핑 중 DB 호출 최소화)
    const key = `${id}-${field}`
    if (typeof value === 'string') {
      if (debounceTimers[key]) clearTimeout(debounceTimers[key])
      debounceTimers[key] = setTimeout(() => {
        supabase
          .from('return_exchange_data')
          .update({ [field]: value })
          .eq('id', id)
          .then(({ error }) => {
            if (error) console.error('저장 실패:', error)
          })
      }, 500)
    } else {
      // 체크박스 등은 즉시 저장
      supabase
        .from('return_exchange_data')
        .update({ [field]: value })
        .eq('id', id)
        .then(({ error }) => {
          if (error) console.error('저장 실패:', error)
        })
    }
  }

  // 주문번호로 정보 자동 불러오기
  const fetchOrderInfo = async (orderNo: string) => {
    console.log('fetchOrderInfo 호출됨, 주문번호:', orderNo)
    if (!orderNo || orderNo.length < 10) {
      console.log('주문번호 길이 부족, 리턴')
      return
    }

    setIsLoadingOrder(true)
    try {
      console.log('API 호출:', `/api/imweb/order?order_no=${orderNo}`)
      const response = await fetch(`/api/imweb/order?order_no=${orderNo}`)
      const result = await response.json()
      console.log('API 응답:', result)

      if (result.success && result.data) {
        const order = result.data
        console.log('주문 정보:', order)
        setFormData(prev => ({
          ...prev,
          recipient: order.recipient,
          original_tracking: order.tracking_no,
          payment_method: order.payment_method,
          // 첫 번째 상품 정보 자동 입력
          ...(order.products?.length > 0 && {
            product_name: order.products[0].name,
            quantity: order.products[0].quantity
          })
        }))
        console.log('폼 데이터 업데이트 완료')
      } else {
        console.log('API 응답 실패 또는 데이터 없음:', result)
        alert('주문 정보를 찾을 수 없습니다: ' + (result.error || '알 수 없는 오류'))
      }
    } catch (error) {
      console.error('주문 정보 조회 실패:', error)
      alert('주문 정보 조회 중 오류 발생: ' + error)
    } finally {
      setIsLoadingOrder(false)
    }
  }

  const handleOrderNoChange = (orderNo: string) => {
    console.log('주문번호 입력:', orderNo, '길이:', orderNo.length)
    setFormData(prev => ({ ...prev, order_no: orderNo }))
    if (orderNo.length >= 10) {
      console.log('API 호출 시작...')
      fetchOrderInfo(orderNo)
    }
  }

  // Supabase에서 데이터 불러오기
  useEffect(() => {
    const fetchReturns = async () => {
      try {
        setIsLoading(true)
        // 모든 데이터 가져오기 (기본 1000개 제한 해제)
        const { data, error } = await supabase
          .from('return_exchange_data')
          .select('*')
          .order('created_at', { ascending: false })
          .range(0, 9999) // 최대 10000개까지 가져오기

        if (error) {
          console.error('데이터 불러오기 실패:', error)
          return
        }

        if (data) {
          setReturnsList(data)
        }
      } catch (error) {
        console.error('데이터 조회 중 오류:', error)
      } finally {
        setIsLoading(false)
      }
    }

    fetchReturns()
  }, [])

  // SKU/바코드 검색 결과 필터링 (띄어쓰기 지원)
  const searchResults = useMemo(() => {
    if (barcodeSearch.length < 2) return []

    const searchTerms = barcodeSearch.toLowerCase().trim().split(/\s+/)
    return skuData.filter(item => {
      const productNameLower = item.product_name.toLowerCase()
      const skuLower = item.sku.toLowerCase()

      // 모든 검색어가 상품명 또는 SKU에 포함되어야 함
      return searchTerms.every(term =>
        productNameLower.includes(term) || skuLower.includes(term)
      )
    }).slice(0, 50) // 최대 50개 표시
  }, [barcodeSearch])

  // SKU/바코드 검색 입력
  const handleBarcodeSearchChange = (value: string) => {
    setBarcodeSearch(value)
    setShowBarcodeResults(value.length >= 2)
  }

  // 상품 추가
  const addProduct = () => {
    setProducts([...products, { category: '', product_name: '', barcode: '', quantity: 1 }])
  }

  // 상품 삭제
  const removeProduct = (index: number) => {
    if (products.length > 1) {
      setProducts(products.filter((_, i) => i !== index))
      if (currentProductIndex >= products.length - 1) {
        setCurrentProductIndex(Math.max(0, currentProductIndex - 1))
      }
    }
  }

  // 상품 정보 업데이트
  const updateProduct = (index: number, field: keyof ProductItem, value: any) => {
    const newProducts = [...products]
    newProducts[index] = { ...newProducts[index], [field]: value }
    setProducts(newProducts)
  }

  // 검색 결과에서 상품 선택
  const handleSelectProduct = (item: typeof skuData[0]) => {
    const category = item.product_name.split('_')[0]

    updateProduct(currentProductIndex, 'product_name', item.product_name)
    updateProduct(currentProductIndex, 'category', category)
    updateProduct(currentProductIndex, 'barcode', item.sku)

    setBarcodeSearch(item.sku)
    setShowBarcodeResults(false)
  }

  // 상세보기에서 SKU 선택
  const handleSelectProductInDetail = (item: typeof skuData[0]) => {
    const category = item.product_name.split('_')[0]

    setNewProduct({
      product_name: item.product_name,
      category: category,
      barcode: item.sku,
      quantity: 1
    })

    setBarcodeSearch(item.sku)
    setShowBarcodeResults(false)
  }

  // 리스트 항목 클릭 - 상세 보기
  const handleRowClick = useCallback(async (item: ReturnExchangeData) => {
    setSelectedItem(item)
    setEditData(item)

    // 같은 주문번호의 모든 제품 가져오기
    if (item.order_no) {
      const related = returnsList.filter(r => r.order_no === item.order_no)
      setRelatedItems(related)
    } else {
      setRelatedItems([item])
    }

    setShowDetailModal(true)
  }, [returnsList])

  // 상세보기 모달 닫기
  const handleCloseDetailModal = () => {
    setShowDetailModal(false)
    setShowAddProductForm(false)
    setNewProduct({ category: '', product_name: '', barcode: '', quantity: 1 })
    setBarcodeSearch('')
    setShowBarcodeResults(false)
  }

  // 상세 정보 업데이트
  const handleUpdate = async () => {
    if (!selectedItem?.id) return

    try {
      const { error } = await supabase
        .from('return_exchange_data')
        .update(editData)
        .eq('id', selectedItem.id)

      if (error) {
        console.error('수정 실패:', error)
        alert('수정 중 오류가 발생했습니다: ' + error.message)
        return
      }

      // 로컬 state 업데이트
      setReturnsList(prev =>
        prev.map(item =>
          item.id === selectedItem.id ? { ...item, ...editData } : item
        )
      )

      handleCloseDetailModal()
      alert('수정되었습니다!')
    } catch (error) {
      console.error('수정 중 오류:', error)
      alert('수정 중 오류가 발생했습니다.')
    }
  }

  // 삭제
  const handleDelete = async () => {
    if (!selectedItem?.id) return
    if (!confirm('정말 삭제하시겠습니까?')) return

    try {
      const { error } = await supabase
        .from('return_exchange_data')
        .delete()
        .eq('id', selectedItem.id)

      if (error) {
        console.error('삭제 실패:', error)
        alert('삭제 중 오류가 발생했습니다: ' + error.message)
        return
      }

      // 로컬 state 업데이트
      setReturnsList(prev => prev.filter(item => item.id !== selectedItem.id))

      handleCloseDetailModal()
      alert('삭제되었습니다!')
    } catch (error) {
      console.error('삭제 중 오류:', error)
      alert('삭제 중 오류가 발생했습니다.')
    }
  }

  // 상세보기에서 상품 추가
  const handleAddProduct = async () => {
    if (!selectedItem) return
    if (!newProduct.category || !newProduct.product_name) {
      alert('카테고리와 상품명을 입력해주세요.')
      return
    }

    try {
      // 기존 주문 정보를 복사하고 새 상품 정보만 교체
      const newEntry = {
        year: selectedItem.year,
        month: selectedItem.month,
        day: selectedItem.day,
        distributor: selectedItem.distributor,
        type: selectedItem.type,
        recipient: selectedItem.recipient,
        original_tracking: selectedItem.original_tracking,
        return_tracking: selectedItem.return_tracking,
        order_no: selectedItem.order_no,
        reason: selectedItem.reason,
        defect_level: selectedItem.defect_level,
        internal_notes: selectedItem.internal_notes,
        customer_voc: selectedItem.customer_voc,
        cash_receipt_issued: selectedItem.cash_receipt_issued,
        amount: selectedItem.amount,
        notes: selectedItem.notes,
        receipt_delivered: selectedItem.receipt_delivered,
        receipt_details: selectedItem.receipt_details,
        payment_method: selectedItem.payment_method,
        // 새 상품 정보
        category: newProduct.category,
        product_name: newProduct.product_name,
        barcode: newProduct.barcode,
        quantity: newProduct.quantity
      }

      const { data, error } = await supabase
        .from('return_exchange_data')
        .insert([newEntry])
        .select()

      if (error) {
        console.error('상품 추가 실패:', error)
        alert('상품 추가 중 오류가 발생했습니다: ' + error.message)
        return
      }

      if (data && data[0]) {
        // 로컬 state 업데이트
        setReturnsList(prev => [data[0], ...prev])
        setRelatedItems(prev => [...prev, data[0]])

        // 폼 초기화
        setNewProduct({ category: '', product_name: '', barcode: '', quantity: 1 })
        setShowAddProductForm(false)
        setBarcodeSearch('')

        alert('상품이 추가되었습니다!')
      }
    } catch (error) {
      console.error('상품 추가 중 오류:', error)
      alert('상품 추가 중 오류가 발생했습니다.')
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()

    try {
      // 각 상품마다 별도의 레코드 생성
      const entries = products.map(product => ({
        ...formData,
        category: product.category,
        product_name: product.product_name,
        barcode: product.barcode,
        quantity: product.quantity
      }))

      // Supabase에 여러 데이터 저장
      const { data: newEntries, error } = await supabase
        .from('return_exchange_data')
        .insert(entries)
        .select()

      if (error) {
        console.error('저장 실패:', error)
        alert('저장 중 오류가 발생했습니다: ' + error.message)
        return
      }

      if (newEntries) {
        // 로컬 state 업데이트
        setReturnsList(prev => [...newEntries, ...prev])
      }

      // 폼 초기화
      setFormData({
        year: new Date().getFullYear(),
        month: new Date().getMonth() + 1,
        day: new Date().getDate(),
        type: '반품',
        defect_level: '미결함',
        cash_receipt_issued: false,
        receipt_delivered: false
      })
      setProducts([{ category: '', product_name: '', barcode: '', quantity: 1 }])
      setBarcodeSearch('')
      setShowForm(false)

      alert(`${products.length}개 상품이 저장되었습니다!`)
    } catch (error) {
      console.error('저장 중 오류:', error)
      alert('저장 중 오류가 발생했습니다.')
    }
  }

  return (
    <main className="min-h-screen bg-background">
      <div className="max-w-full mx-auto px-8 py-10">
        {/* 헤더 */}
        <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-text-primary mb-2">
              반품/교환 관리
            </h1>
            <p className="text-sm text-text-muted">
              반품 및 교환 요청 처리 현황
            </p>
          </div>
          <Button variant="primary" onClick={() => setShowForm(true)}>
            + 라벨링 추가
          </Button>
        </div>

        {/* 탭 */}
        <div className="mb-6 flex gap-2">
          <button
            onClick={() => setActiveTab('rug')}
            className={`px-6 py-3 rounded-lg font-semibold transition-all ${
              activeTab === 'rug'
                ? 'bg-brand-primary text-white shadow-md'
                : 'bg-white text-text-secondary border border-border hover:bg-background-hover'
            }`}
          >
            🏠 러그/기타 ({returnsList.filter(item => !isFurniture(item.category || '')).length})
          </button>
          <button
            onClick={() => setActiveTab('furniture')}
            className={`px-6 py-3 rounded-lg font-semibold transition-all ${
              activeTab === 'furniture'
                ? 'bg-brand-primary text-white shadow-md'
                : 'bg-white text-text-secondary border border-border hover:bg-background-hover'
            }`}
          >
            🪑 가구 ({returnsList.filter(item => isFurniture(item.category || '')).length})
          </button>
        </div>

        {/* 입력 폼 모달 */}
        {showForm && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4" onClick={() => setShowForm(false)}>
            <div className="bg-white rounded-2xl shadow-xl max-w-4xl w-full max-h-[90vh] flex flex-col" onClick={(e) => e.stopPropagation()}>
              {/* 헤더 */}
              <div className="flex-none bg-white border-b border-border px-6 py-4 flex items-center justify-between rounded-t-2xl">
                <h2 className="text-xl font-bold text-text-primary">반품/교환 등록</h2>
                <button
                  onClick={() => setShowForm(false)}
