                  </button>
                </div>
              </div>
            )}
              </>
            )}
          </div>
        )}

        {/* 상세 정보 모달 */}
        {showDetailModal && selectedItem && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-xl max-w-4xl w-full max-h-[90vh] flex flex-col">
              <div className="flex-none bg-white border-b border-border px-6 py-3 flex items-center justify-between rounded-t-2xl">
                <div>
                  <h2 className="text-lg font-bold text-text-primary">
                    반품/교환 상세
                    {relatedItems.length > 1 && (
                      <span className="ml-2 text-sm bg-brand-primary text-white px-2 py-0.5 rounded-full">
                        {relatedItems.length}개 제품
                      </span>
                    )}
                  </h2>
                  <p className="text-xs text-text-tertiary mt-0.5">주문번호: {selectedItem.order_no} · {selectedItem.recipient}</p>
                </div>
                <button
                  onClick={() => handleCloseDetailModal()}
                  className="text-text-tertiary hover:text-text-primary text-xl w-8 h-8 flex items-center justify-center"
                >
                  ✕
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-5 grid grid-cols-2 gap-4">
                {/* 왼쪽 컬럼 */}
                <div className="space-y-3">
                  {/* 기본 정보 섹션 */}
                  <div className="bg-background-muted rounded-lg p-4">
                    <h3 className="text-sm font-semibold text-text-primary mb-2 flex items-center gap-2">
                      <span className="text-brand-primary">📋</span> 기본 정보
                    </h3>
                    <div className="grid grid-cols-4 gap-3">
                      <div className="col-span-2">
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">날짜</label>
                        <input
                          type="date"
                          value={editData.year && editData.month && editData.day
                            ? `${editData.year}-${String(editData.month).padStart(2, '0')}-${String(editData.day).padStart(2, '0')}`
                            : ''}
                          onChange={(e) => {
                            const [y, m, d] = e.target.value.split('-').map(Number)
                            setEditData({ ...editData, year: y, month: m, day: d })
                          }}
                          className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                        />
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">유통사</label>
                        <select
                          value={editData.distributor || ''}
                          onChange={(e) => setEditData({ ...editData, distributor: e.target.value })}
                          className="w-full px-2 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                        >
                          {distributors.map(d => (
                            <option key={d} value={d}>{d}</option>
                          ))}
                        </select>
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">유형</label>
                        <select
                          value={editData.type}
                          onChange={(e) => setEditData({ ...editData, type: e.target.value as '교환' | '반품' })}
                          className="w-full px-2 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                        >
                          <option value="반품">반품</option>
                          <option value="교환">교환</option>
                        </select>
                      </div>
                    </div>
                  </div>

                  {/* 주문 정보 섹션 */}
                  <div className="bg-background-muted rounded-lg p-4">
                    <h3 className="text-sm font-semibold text-text-primary mb-2 flex items-center gap-2">
                      <span className="text-brand-primary">📦</span> 주문 정보
                    </h3>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">주문번호</label>
                        <input
                          type="text"
                          value={editData.order_no || ''}
                          onChange={(e) => setEditData({ ...editData, order_no: e.target.value })}
                          className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                        />
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">바코드 (SKU)</label>
                        <input
                          type="text"
                          value={editData.barcode || ''}
                          onChange={(e) => setEditData({ ...editData, barcode: e.target.value })}
                          className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary font-mono"
                          placeholder="SKU 번호"
                        />
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">수취인</label>
                        <input
                          type="text"
                          value={editData.recipient || ''}
                          onChange={(e) => setEditData({ ...editData, recipient: e.target.value })}
                          className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                        />
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                        <div>
                          <label className="block text-xs font-semibold text-text-primary mb-1.5">원송장번호</label>
                          <input
                            type="text"
                            value={editData.original_tracking || ''}
                            onChange={(e) => setEditData({ ...editData, original_tracking: e.target.value })}
                            className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                            placeholder="출고"
                          />
                        </div>

                        <div>
                          <label className="block text-xs font-semibold text-text-primary mb-1.5">반송장번호</label>
                          <input
                            type="text"
                            value={editData.return_tracking || ''}
                            onChange={(e) => setEditData({ ...editData, return_tracking: e.target.value })}
                            className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                            placeholder="회수"
                          />
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* 상품 정보 섹션 */}
                  <div className="bg-background-muted rounded-lg p-4">
                    <div className="flex items-center justify-between mb-2">
                      <h3 className="text-sm font-semibold text-text-primary flex items-center gap-2">
                        <span className="text-brand-primary">🏷️</span> 상품 정보
                        {relatedItems.length > 1 && (
                          <span className="text-xs bg-brand-primary text-white px-2 py-0.5 rounded-full">
                            {relatedItems.length}개 제품
                          </span>
                        )}
                      </h3>
                      <button
                        onClick={() => setShowAddProductForm(!showAddProductForm)}
                        className="text-xs px-3 py-1 bg-brand-primary text-white rounded hover:bg-opacity-90 transition-all"
                      >
                        {showAddProductForm ? '취소' : '+ 상품 추가'}
                      </button>
                    </div>

                    {/* 상품 추가 폼 */}
                    {showAddProductForm && (
                      <div className="mb-3 p-3 bg-white border-2 border-brand-primary rounded-lg">
                        <h4 className="text-xs font-bold text-brand-primary mb-2">새 상품 추가</h4>

                        {/* SKU 검색 */}
                        <div className="mb-2 relative">
                          <input
                            type="text"
                            value={barcodeSearch}
                            onChange={(e) => {
                              setBarcodeSearch(e.target.value)
                              setShowBarcodeResults(e.target.value.length >= 2)
                            }}
                            placeholder="바코드/SKU 검색 (상품명 또는 SKU)"
                            className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          />

                          {/* 검색 결과 */}
                          {showBarcodeResults && searchResults.length > 0 && (
                            <div className="absolute z-10 w-full mt-1 bg-white border border-border rounded-lg shadow-lg max-h-48 overflow-y-auto">
                              {searchResults.slice(0, 10).map((item, index) => (
                                <button
                                  key={index}
                                  type="button"
                                  onClick={() => handleSelectProductInDetail(item)}
                                  className="w-full px-3 py-2 text-left hover:bg-background-hover text-sm border-b border-border last:border-0"
                                >
                                  <div className="font-medium text-text-primary">{item.product_name}</div>
                                  <div className="text-xs text-text-tertiary font-mono mt-0.5">{item.sku}</div>
                                </button>
                              ))}
                            </div>
                          )}
                        </div>

                        {/* 상품 정보 입력 */}
                        <div className="grid grid-cols-2 gap-2 mb-2">
                          <div>
                            <label className="block text-xs text-text-tertiary mb-1">카테고리 *</label>
                            <input
                              type="text"
                              value={newProduct.category}
                              onChange={(e) => setNewProduct({ ...newProduct, category: e.target.value })}
                              className="w-full px-2 py-1 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                              placeholder="예: 미니멀러그"
                            />
                          </div>
                          <div>
                            <label className="block text-xs text-text-tertiary mb-1">수량</label>
                            <input
                              type="number"
                              value={newProduct.quantity}
                              onChange={(e) => setNewProduct({ ...newProduct, quantity: parseInt(e.target.value) || 1 })}
                              className="w-full px-2 py-1 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                            />
                          </div>
                        </div>

                        <div className="mb-2">
                          <label className="block text-xs text-text-tertiary mb-1">상품명 *</label>
                          <input
                            type="text"
                            value={newProduct.product_name}
                            onChange={(e) => setNewProduct({ ...newProduct, product_name: e.target.value })}
                            className="w-full px-2 py-1 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                            placeholder="상품명"
                          />
                        </div>

                        <div className="mb-2">
                          <label className="block text-xs text-text-tertiary mb-1">바코드</label>
                          <input
                            type="text"
                            value={newProduct.barcode}
                            onChange={(e) => setNewProduct({ ...newProduct, barcode: e.target.value })}
                            className="w-full px-2 py-1 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary font-mono"
                            placeholder="바코드/SKU"
                          />
                        </div>

                        <button
                          onClick={handleAddProduct}
                          className="w-full px-3 py-1.5 bg-brand-primary text-white text-sm rounded hover:bg-opacity-90 font-semibold"
                        >
                          저장
                        </button>
                      </div>
                    )}

                    <div className="space-y-2">
                      {relatedItems.map((product, index) => (
                        <div key={product.id || index} className={`p-3 rounded-lg ${index === 0 ? 'bg-white border-2 border-brand-primary' : 'bg-white border border-border'}`}>
                          <div className="flex items-start justify-between mb-2">
                            <div className="flex items-center gap-2">
                              <span className="text-xs font-bold text-brand-primary">#{index + 1}</span>
                              <Badge variant="primary">{product.category}</Badge>
                            </div>
                            <span className="text-xs text-text-tertiary">수량: {product.quantity}</span>
                          </div>
                          <p className="text-sm text-text-primary font-medium">{product.product_name}</p>
                          {product.barcode && (
                            <p className="text-xs text-text-tertiary mt-1">바코드: {product.barcode}</p>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* 오른쪽 컬럼 */}
                <div className="space-y-3">
                  {/* 반품/교환 상세 섹션 */}
                  <div className="bg-background-muted rounded-lg p-4">
                    <h3 className="text-sm font-semibold text-text-primary mb-2 flex items-center gap-2">
                      <span className="text-brand-primary">🔄</span> 반품/교환 상세
                    </h3>
                    <div className="space-y-3">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                          <label className="block text-xs font-semibold text-text-primary mb-1.5">사유</label>
                          <select
                            value={editData.reason || ''}
                            onChange={(e) => setEditData({ ...editData, reason: e.target.value })}
                            className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          >
                            <option value="">선택</option>
                            {reasons.map(r => (
                              <option key={r} value={r}>{r}</option>
                            ))}
                          </select>
                        </div>

                        <div>
                          <label className="block text-xs font-semibold text-text-primary mb-1.5">불량정도</label>
                          <select
                            value={editData.defect_level}
                            onChange={(e) => setEditData({ ...editData, defect_level: e.target.value as '미결함' | '경결함' })}
                            className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          >
                            <option value="미결함">미결함</option>
                            <option value="경결함">경결함</option>
                          </select>
                        </div>
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">현금영수증 내용</label>
                        <input
                          type="text"
                          value={editData.receipt_details || ''}
                          onChange={(e) => setEditData({ ...editData, receipt_details: e.target.value })}
                          className="w-full px-3 py-1.5 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          placeholder="010-000-1234"
                        />
                      </div>
                    </div>
                  </div>

                  {/* 메모 섹션 */}
                  <div className="bg-background-muted rounded-lg p-4">
                    <h3 className="text-sm font-semibold text-text-primary mb-2 flex items-center gap-2">
                      <span className="text-brand-primary">📝</span> 메모
                    </h3>
                    <div className="space-y-3">
                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">내부 전달사항</label>
                        <textarea
                          value={editData.internal_notes || ''}
                          onChange={(e) => setEditData({ ...editData, internal_notes: e.target.value })}
                          rows={3}
                          className="w-full px-3 py-2 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          placeholder="CX/QC팀 전달사항"
                        />
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">고객 VOC</label>
                        <textarea
                          value={editData.customer_voc || ''}
                          onChange={(e) => setEditData({ ...editData, customer_voc: e.target.value })}
                          rows={3}
                          className="w-full px-3 py-2 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          placeholder="고객 의견"
                        />
                      </div>

                      <div>
                        <label className="block text-xs font-semibold text-text-primary mb-1.5">기타 메모</label>
                        <textarea
                          value={editData.notes || ''}
                          onChange={(e) => setEditData({ ...editData, notes: e.target.value })}
                          rows={2}
                          className="w-full px-3 py-2 text-sm border border-border rounded focus:ring-2 focus:ring-brand-primary"
                          placeholder="추가 메모"
                        />
                      </div>

                      <div className="space-y-2 pt-1">
                        <div className="flex items-center gap-2 p-2.5 bg-white rounded border border-border">
                          <input
                            type="checkbox"
                            checked={editData.cash_receipt_issued || false}
                            onChange={(e) => setEditData({ ...editData, cash_receipt_issued: e.target.checked })}
                            className="w-4 h-4 text-brand-primary rounded"
                          />
                          <label className="text-xs font-medium text-text-primary">현금영수증 발행</label>
                        </div>

                        <div className="flex items-center gap-2 p-2.5 bg-white rounded border border-border">
                          <input
                            type="checkbox"
                            checked={editData.receipt_delivered || false}
                            onChange={(e) => setEditData({ ...editData, receipt_delivered: e.target.checked })}
                            className="w-4 h-4 text-brand-primary rounded"
                          />
                          <label className="text-xs font-medium text-text-primary">영수증 전달 완료</label>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* 버튼 */}
              <div className="flex-none bg-white border-t border-border px-6 py-3 flex justify-between items-center rounded-b-2xl">
                <Button variant="error" onClick={handleDelete} className="px-4 py-1.5 text-sm">
                  🗑️ 삭제
                </Button>
                <div className="flex gap-2">
                  <Button variant="secondary" onClick={() => handleCloseDetailModal()} className="px-6 py-1.5 text-sm">
                    취소
                  </Button>
                  <Button variant="primary" onClick={handleUpdate} className="px-6 py-1.5 text-sm">
                    💾 저장
                  </Button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </main>
  )
}

