'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'

const tables = [
  { name: 'manufacturer_shipment_data', label: '제조사 출고' },
  { name: 'tpl_shipment_data', label: '3PL 출고' },
  { name: 'daily_sales_data', label: '판매 데이터' },
  { name: 'return_exchange_data', label: '반품/교환' },
  { name: 'cost_data', label: '원가' },
  { name: 'set_price_data', label: '세트 가격' },
  { name: 'subsidiary_data', label: '단가 마스터' },
  { name: 'set_composition', label: '세트 구성' },
  { name: 'product_barcode_simple_name', label: '바코드 매핑' },
]

export default function DataViewerPage() {
  const [selectedTable, setSelectedTable] = useState(tables[0].name)
  const [data, setData] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [totalCount, setTotalCount] = useState(0)

  useEffect(() => {
    fetchData()
  }, [selectedTable])

  const fetchData = async () => {
    setLoading(true)
    setError(null)

    try {
      // 전체 개수 가져오기
      const { count } = await supabase
        .from(selectedTable)
        .select('*', { count: 'exact', head: true })

      setTotalCount(count || 0)

      // 데이터 가져오기 (최대 100개)
      const { data: result, error: fetchError } = await supabase
        .from(selectedTable)
        .select('*')
        .limit(100)

      if (fetchError) {
        setError(fetchError.message)
      } else {
        setData(result || [])
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : '알 수 없는 오류')
    } finally {
      setLoading(false)
    }
  }

  const downloadJSON = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${selectedTable}_${new Date().toISOString().split('T')[0]}.json`
    a.click()
  }

  const columns = data.length > 0 ? Object.keys(data[0]) : []

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-full mx-auto">
        <h1 className="text-3xl font-bold mb-6">데이터 뷰어</h1>

        {/* 테이블 선택 */}
        <div className="mb-6 flex gap-4 items-center">
          <select
            value={selectedTable}
            onChange={(e) => setSelectedTable(e.target.value)}
            className="px-4 py-2 border border-gray-300 rounded-lg"
          >
            {tables.map(table => (
              <option key={table.name} value={table.name}>
                {table.label} ({table.name})
              </option>
            ))}
          </select>

          <button
            onClick={fetchData}
            className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
          >
            새로고침
          </button>

          <button
            onClick={downloadJSON}
            disabled={data.length === 0}
            className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 disabled:bg-gray-300"
          >

