      }
    } catch (err) {
      setError(err instanceof Error ? err.message : '알 수 없는 오류')
    } finally {
      setLoading(false)
    }
  }

  const downloadJSON = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${selectedTable}_${new Date().toISOString().split('T')[0]}.json`
    a.click()
  }

  const columns = data.length > 0 ? Object.keys(data[0]) : []

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-full mx-auto">
        <h1 className="text-3xl font-bold mb-6">데이터 뷰어</h1>

        {/* 테이블 선택 */}
        <div className="mb-6 flex gap-4 items-center">
          <select
            value={selectedTable}
            onChange={(e) => setSelectedTable(e.target.value)}
            className="px-4 py-2 border border-gray-300 rounded-lg"
          >
            {tables.map(table => (
              <option key={table.name} value={table.name}>
                {table.label} ({table.name})
              </option>
            ))}
          </select>

          <button
            onClick={fetchData}
            className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
          >
            새로고침
          </button>

          <button
            onClick={downloadJSON}
            disabled={data.length === 0}
            className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 disabled:bg-gray-300"
          >
            JSON 다운로드
          </button>

          <div className="ml-auto text-sm text-gray-600">
            전체: {totalCount.toLocaleString()}개 | 표시: {data.length}개
          </div>
        </div>

        {/* 로딩/에러 */}
        {loading && (
          <div className="text-center py-12">
            <div className="inline-block w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="mt-4 text-gray-600">데이터 불러오는 중...</p>
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 text-red-700">
            오류: {error}
          </div>
        )}

        {/* 데이터 테이블 */}
        {!loading && !error && data.length > 0 && (
          <div className="bg-white rounded-lg shadow overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-gray-100">
                  <tr>
                    {columns.map(col => (
                      <th key={col} className="px-4 py-3 text-left font-semibold text-gray-700">
                        {col}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {data.map((row, i) => (
                    <tr key={i} className="hover:bg-gray-50">
                      {columns.map(col => (
                        <td key={col} className="px-4 py-2 text-gray-700">
                          {typeof row[col] === 'object' && row[col] !== null
                            ? JSON.stringify(row[col])
                            : String(row[col] ?? '')}
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {!loading && !error && data.length === 0 && (
          <div className="bg-white rounded-lg shadow p-12 text-center text-gray-500">
            데이터가 없습니다
          </div>
        )}
      </div>
    </div>
  )
}

