import { NextResponse } from 'next/server'

export async function GET(request: Request) {
  try {
    const apiKey = process.env.IMWEB_API_KEY
    const secretKey = process.env.IMWEB_SECRET_KEY

    if (!apiKey || !secretKey) {
      return NextResponse.json(
        { error: 'API 키가 설정되지 않았습니다.' },
        { status: 500 }
      )
    }

    // URL에서 주문번호 가져오기
    const { searchParams } = new URL(request.url)
    const orderNo = searchParams.get('order_no')

    if (!orderNo) {
      return NextResponse.json(
        { error: '주문번호를 입력해주세요.' },
        { status: 400 }
      )
    }

    // 1단계: 액세스 토큰 발급
    const authResponse = await fetch('https://api.imweb.me/v2/auth', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        key: apiKey,
        secret: secretKey
      })
    })

    const authResult = await authResponse.json()

    if (!authResult.access_token) {
      return NextResponse.json({
        success: false,
        error: '토큰 발급 실패',
        details: authResult
      }, { status: 500 })
    }

    const accessToken = authResult.access_token

    // 2단계: 특정 주문 조회
    const orderResponse = await fetch(
      `https://api.imweb.me/v2/shop/orders/${orderNo}`,
      {
        method: 'GET',
        headers: {
          'access-token': accessToken,
          'Content-Type': 'application/json',
        }
      }
    )

    const orderResult = await orderResponse.json()
    console.log('Order detail response:', JSON.stringify(orderResult, null, 2))

    if (orderResult.code === 200 && orderResult.data) {
      const order = orderResult.data

      // 필요한 정보만 추출
      const orderInfo = {
        order_no: order.order_no,
        recipient: order.delivery?.address?.name || order.orderer?.name,
        orderer_name: order.orderer?.name,
        orderer_phone: order.orderer?.call,
        recipient_phone: order.delivery?.address?.phone,
        address: order.delivery?.address ?
          `${order.delivery.address.address} ${order.delivery.address.address_detail}` : '',
        tracking_no: order.delivery?.tracking_no || '',
        payment_method: order.payment?.pay_type || '',
        total_price: order.payment?.total_price || 0,
        delivery_price: order.payment?.deliv_price || 0,
        payment_amount: order.payment?.payment_amount || 0,
        delivery_memo: order.delivery?.memo || '',
        order_date: order.order_time ? new Date(order.order_time * 1000).toISOString() : '',
        products: [] // 아임웹 API는 상품 정보를 제공하지 않음
      }

      return NextResponse.json({
        success: true,
        data: orderInfo
      })
    }

    return NextResponse.json({
      success: false,
      error: '주문 정보를 찾을 수 없습니다.',
      details: orderResult
    }, { status: 404 })

  } catch (error) {
    console.error('주문 조회 오류:', error)
    return NextResponse.json(
      {
        success: false,
        error: 'API 호출 중 오류가 발생했습니다.',
        details: error instanceof Error ? error.message : String(error)
      },
      { status: 500 }
    )
  }
}

