  // ... 나머지 템플릿은 너무 길어서 생략 (초기 로드 버튼으로 추가)
]

interface Props {
  initialTemplates: Template[]
}

export default function CSGuideClient({ initialTemplates }: Props) {
  const [templates, setTemplates] = useState<Template[]>(initialTemplates)
  const [selectedCategory, setSelectedCategory] = useState<string>('기본')
  const [selectedSubcategory, setSelectedSubcategory] = useState<string>('전체')
  const [searchQuery, setSearchQuery] = useState('')
  const [copiedId, setCopiedId] = useState<number | null>(null)
  const [showModal, setShowModal] = useState(false)
  const [editingTemplate, setEditingTemplate] = useState<Template | null>(null)
  const [isLoading, setIsLoading] = useState(false)

  // 메인 카테고리 목록
  const categories = [
    '기본',
    '반품',
    '교환',
    '보상',
    '자주하는 질문',
    '주문제작-제작 가능',
    '주문제작-제작 불가',
    '무료배송 정책'
  ]

  // 자주하는 질문의 서브카테고리
  const faqSubcategories = [
    '전체',
    '배송·출고',
    '제품 관리',
    '주문·결제·혜택',
    '사용 환경 및 기능',
    '클레임',
    '상품 비교·스펙',
    '기타'
  ]

  // 템플릿 필터링
  const filteredTemplates = templates.filter(template => {
    const matchesCategory = template.category === selectedCategory
    const matchesSubcategory = selectedCategory !== '자주하는 질문' ||
                               selectedSubcategory === '전체' ||
                               template.subcategory === selectedSubcategory
    const matchesSearch = searchQuery === '' ||
                          template.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          template.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          template.tags?.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()))
    return matchesCategory && matchesSubcategory && matchesSearch
  })

  // 템플릿 복사
  const copyToClipboard = (text: string, id: number) => {
    navigator.clipboard.writeText(text)
    setCopiedId(id)
    setTimeout(() => setCopiedId(null), 2000)
  }

  // 카테고리 변경
  const handleCategoryChange = (category: string) => {
    setSelectedCategory(category)
    if (category === '자주하는 질문') {
      setSelectedSubcategory('전체')
    }
  }

  // 템플릿 추가/수정
  const handleSaveTemplate = async (template: Omit<Template, 'id' | 'created_at' | 'updated_at'>) => {
    setIsLoading(true)
    try {
      if (editingTemplate?.id) {
        // 수정
        const { error } = await supabase
          .from('cs_templates')
          .update(template)
          .eq('id', editingTemplate.id)

        if (error) throw error

        // 로컬 상태 업데이트
        setTemplates(templates.map(t =>
          t.id === editingTemplate.id ? { ...t, ...template } : t
        ))
      } else {
        // 추가
        const { data, error } = await supabase
          .from('cs_templates')
          .insert([template])
          .select()

        if (error) throw error
        if (data) setTemplates([...templates, ...data])
      }

      setShowModal(false)
      setEditingTemplate(null)
      alert(editingTemplate ? '템플릿이 수정되었습니다.' : '템플릿이 추가되었습니다.')
    } catch (error) {
      console.error('저장 오류:', error)
      alert('저장 중 오류가 발생했습니다.')
    } finally {
      setIsLoading(false)
    }
  }

  // 템플릿 삭제
  const handleDeleteTemplate = async (id: number) => {
    if (!confirm('정말 삭제하시겠습니까?')) return

    setIsLoading(true)
    try {
      const { error } = await supabase
        .from('cs_templates')
        .delete()
        .eq('id', id)

      if (error) throw error

      setTemplates(templates.filter(t => t.id !== id))
      alert('템플릿이 삭제되었습니다.')
    } catch (error) {
      console.error('삭제 오류:', error)
      alert('삭제 중 오류가 발생했습니다.')
    } finally {
      setIsLoading(false)
    }
  }

  // 새 템플릿 추가 모달 열기
  const openAddModal = () => {
    setEditingTemplate(null)
    setShowModal(true)
  }

  // 템플릿 수정 모달 열기
  const openEditModal = (template: Template) => {
    setEditingTemplate(template)
    setShowModal(true)
  }

  // 페이지 새로고침
  const refreshTemplates = async () => {
    const { data } = await supabase
      .from('cs_templates')
      .select('*')
      .order('created_at', { ascending: true })

    if (data) setTemplates(data)
  }

  return (
    <main className="min-h-screen bg-background">
      <div className="max-w-[1800px] mx-auto px-8 py-10 flex gap-6">
        {/* 왼쪽: 템플릿 영역 */}
        <div className="flex-1">
          {/* 헤더 */}
          <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-text-primary mb-2">
              📖 CS 가이드
            </h1>
            <p className="text-sm text-text-muted">
              고객 응대 템플릿 및 가이드 ({templates.length}개)
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="secondary" size="sm" onClick={refreshTemplates}>
              🔄 새로고침
            </Button>
            <Button variant="primary" size="sm" onClick={openAddModal}>
              ➕ 새 템플릿
            </Button>
          </div>
        </div>

        {/* 검색 */}
        <div className="mb-6">
          <input
            type="text"
            placeholder="템플릿 검색... (Ctrl+F 가능)"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full px-4 py-3 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-brand-primary"
          />
        </div>

        {/* 메인 카테고리 탭 */}
        <div className="mb-6">
          <div className="flex gap-2 overflow-x-auto pb-2">
            {categories.map(category => (
              <button
                key={category}
                onClick={() => handleCategoryChange(category)}
                className={`px-4 py-2 rounded-lg font-medium whitespace-nowrap transition-colors ${
                  selectedCategory === category
                    ? 'bg-brand-primary text-white'
                    : 'bg-background-muted text-text-tertiary hover:bg-background-hover'
                }`}
              >
                {category === '자주하는 질문' ? '⭐ 자주하는 질문' : category}
              </button>
            ))}
          </div>
        </div>

        {/* 자주하는 질문 서브카테고리 */}
        {selectedCategory === '자주하는 질문' && (
          <div className="mb-6">
            <div className="flex gap-2 overflow-x-auto pb-2">
              {faqSubcategories.map(subcategory => (
                <button
                  key={subcategory}
                  onClick={() => setSelectedSubcategory(subcategory)}
                  className={`px-3 py-1.5 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${
                    selectedSubcategory === subcategory
                      ? 'bg-blue-500 text-white'
                      : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  {subcategory}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* 템플릿 목록 */}
        <div className="space-y-4">
          <h2 className="text-xl font-bold text-text-primary">
            템플릿 ({filteredTemplates.length}개)
          </h2>

          {filteredTemplates.map(template => (
            <Card key={template.id} className="p-6 hover:shadow-md transition-shadow">
              <div className="flex items-start justify-between mb-4">
                <div>
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-lg font-bold text-text-primary">{template.title}</h3>
                    <Badge variant="neutral">{template.category}</Badge>
                    {template.subcategory && (
                      <Badge variant="primary" size="sm">{template.subcategory}</Badge>
                    )}
                  </div>
                  {template.tags && template.tags.length > 0 && (
                    <div className="flex gap-2">
                      {template.tags.map(tag => (
                        <Badge key={tag} variant="primary" size="sm">
                          {tag}
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="secondary"
                    size="sm"
                    onClick={() => openEditModal(template)}
                  >
                    ✏️ 수정
                  </Button>
                  <Button
                    variant={copiedId === template.id ? 'success' : 'primary'}
                    size="sm"
                    onClick={() => copyToClipboard(template.content, template.id!)}
                  >
                    {copiedId === template.id ? '✓ 복사됨' : '복사'}
                  </Button>
                  <Button
                    variant="error"
                    size="sm"
                    onClick={() => handleDeleteTemplate(template.id!)}
                  >
                    🗑️
                  </Button>
                </div>
              </div>

              <pre
                className="whitespace-pre-wrap text-sm text-text-secondary bg-background-muted p-4 rounded-lg font-sans"
                dangerouslySetInnerHTML={{
                  __html: template.highlight
                    ? template.content.replace(/\*\*(.*?)\*\*/g, '<mark style="background-color: #fef08a; padding: 2px 4px; border-radius: 3px; font-weight: 600;">$1</mark>')
                    : template.content
                }}
              />
            </Card>
          ))}

          {filteredTemplates.length === 0 && (
            <Card className="p-12 text-center">
              <p className="text-text-tertiary">검색 결과가 없습니다.</p>
            </Card>
          )}
        </div>

        {/* 템플릿 추가/수정 모달 */}
        {showModal && (
          <TemplateModal
            template={editingTemplate}
            categories={categories}
            faqSubcategories={faqSubcategories}
            onSave={handleSaveTemplate}
            onClose={() => {
              setShowModal(false)
              setEditingTemplate(null)
            }}
            isLoading={isLoading}
          />
        )}
        </div>

        {/* 우측: 가이드 & 메모장 */}
        <div className="w-96 space-y-6">
          {/* CS 가이드 & 정책 (통합) */}
          <Card className="p-6">
            {/* CS 톤 가이드 */}
            <div className="mb-6">
              <h2 className="text-xl font-bold text-text-primary mb-4">📌 CS 톤 가이드</h2>
              <div className="space-y-3 text-sm text-text-secondary">
                <div className="flex items-start gap-2">
                  <span className="text-brand-success font-bold">✓</span>
                  <span>친근하고 따뜻한 톤으로 응대</span>
                </div>
                <div className="flex items-start gap-2">
                  <span className="text-brand-success font-bold">✓</span>
                  <span>이모지 적절히 사용 (☺️, 🏠, :) 등)</span>
                </div>
                <div className="flex items-start gap-2">
                  <span className="text-brand-success font-bold">✓</span>
                  <span>불편사항에 공감과 사과 우선 표현</span>
                </div>
                <div className="flex items-start gap-2">
                  <span className="text-brand-success font-bold">✓</span>
                  <span>"for Mindful Life 라익디스" 서명 필수</span>
                </div>
                <div className="flex items-start gap-2">
                  <span className="text-brand-success font-bold">✓</span>
                  <span>명확하고 상세한 안내 제공</span>
                </div>
              </div>
            </div>

            {/* 구분선 */}
            <div className="border-t border-border my-6"></div>

            {/* 주요 정책 */}
            <div>
              <h2 className="text-xl font-bold text-text-primary mb-4">💰 주요 정책</h2>
              <div className="space-y-4 text-sm">
                <div>
                  <h3 className="font-semibold text-text-primary mb-1">반품/교환 배송비</h3>
                  <p className="text-text-secondary">왕복 7,000원</p>
                </div>
                <div>
                  <h3 className="font-semibold text-text-primary mb-1">무상 AS</h3>
                  <p className="text-text-secondary">구매 후 1년</p>
                </div>
                <div>
                  <h3 className="font-semibold text-text-primary mb-1">불량 보상</h3>
                  <p className="text-text-secondary">경미한 불량: 10% / 보통: 20% / 광범위: 30%</p>
                </div>
                <div>
                  <h3 className="font-semibold text-text-primary mb-1">입금 계좌</h3>
                  <p className="text-text-secondary">기업은행 222-098680-01-029 (㈜라익디스)</p>
                </div>
              </div>
            </div>
          </Card>

          {/* 일별 메모장 */}
          <DailyNoteWidget />
        </div>
      </div>
    </main>
  )
}

// 템플릿 추가/수정 모달 컴포넌트
function TemplateModal({
  template,
  categories,
  faqSubcategories,
  onSave,
  onClose,
  isLoading
}: {
  template: Template | null
  categories: string[]
  faqSubcategories: string[]
  onSave: (template: Omit<Template, 'id' | 'created_at' | 'updated_at'>) => void
  onClose: () => void
  isLoading: boolean
}) {
  const [formData, setFormData] = useState({
    category: template?.category || '기본',
    subcategory: template?.subcategory || '',
    title: template?.title || '',
    content: template?.content || '',
    tags: template?.tags?.join(', ') || '',
    highlight: template?.highlight || false
  })

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    onSave({
      category: formData.category,
      subcategory: formData.subcategory || null,
      title: formData.title,
      content: formData.content,
      tags: formData.tags.split(',').map(t => t.trim()).filter(Boolean),
      highlight: formData.highlight
    })
  }

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg max-w-3xl w-full max-h-[90vh] overflow-y-auto p-6">
        <h2 className="text-2xl font-bold mb-4">
          {template ? '템플릿 수정' : '새 템플릿 추가'}
        </h2>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">카테고리 *</label>
            <select
              value={formData.category}
              onChange={(e) => setFormData({ ...formData, category: e.target.value })}
              className="w-full px-3 py-2 border rounded-lg"
              required
            >
              {categories.map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
          </div>

          {formData.category === '자주하는 질문' && (
            <div>
              <label className="block text-sm font-medium mb-1">서브카테고리</label>
              <select
                value={formData.subcategory}
                onChange={(e) => setFormData({ ...formData, subcategory: e.target.value })}
                className="w-full px-3 py-2 border rounded-lg"
              >
                <option value="">선택 안함</option>
                {faqSubcategories.filter(s => s !== '전체').map(sub => (
                  <option key={sub} value={sub}>{sub}</option>
                ))}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-medium mb-1">제목 *</label>
            <input
              type="text"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              className="w-full px-3 py-2 border rounded-lg"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">내용 * (** 로 감싸면 노란색 강조)</label>
            <textarea
              value={formData.content}
              onChange={(e) => setFormData({ ...formData, content: e.target.value })}
              className="w-full px-3 py-2 border rounded-lg font-mono"
              rows={15}
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">태그 (쉼표로 구분)</label>
            <input
              type="text"
              value={formData.tags}
              onChange={(e) => setFormData({ ...formData, tags: e.target.value })}
              className="w-full px-3 py-2 border rounded-lg"
              placeholder="예: 반품, 배송비, 입금"
            />
          </div>

          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              id="highlight"
              checked={formData.highlight}
              onChange={(e) => setFormData({ ...formData, highlight: e.target.checked })}
              className="w-4 h-4"
            />
            <label htmlFor="highlight" className="text-sm">가격 하이라이트 활성화</label>
          </div>

          <div className="flex gap-2 justify-end">
            <Button type="button" variant="secondary" onClick={onClose} disabled={isLoading}>
              취소
            </Button>
            <Button type="submit" variant="primary" disabled={isLoading}>
              {isLoading ? '저장 중...' : '저장'}
            </Button>
          </div>
        </form>
      </div>
    </div>
  )
}
